        # 30. Pool/Cache/Buffer patterns
        if any(x in short_lower for x in ['pool', 'cache', 'buffer', 'queue', 'stack']):
            self.discovered_patterns['cache'] += 1
            return ('Service', 75.0)

        # 31. Auth/Permission/Access patterns
        if any(x in short_lower for x in ['auth', 'permission', 'access', 'grant', 'deny', 'role', 'acl']):
            self.discovered_patterns['auth'] += 1
            return ('Guard', 75.0)

        # 32. Log/Trace/Debug patterns
        if any(x in short_lower for x in ['log', 'trace', 'debug', 'audit', 'metric', 'stat']):
            self.discovered_patterns['logging'] += 1
            return ('Utility', 75.0)

        # 33. Template/Render patterns
        if any(x in short_lower for x in ['template', 'render', 'generate', 'emit', 'produce']):
            self.discovered_patterns['template'] += 1
            return ('Factory', 75.0)

        # 34. Import/Export patterns
        if any(x in short_lower for x in ['import', 'export', 'ingest', 'extract', 'download', 'upload']):
            self.discovered_patterns['importexport'] += 1
            return ('Service', 75.0)

        # 35. Iterator/Generator patterns
        if any(x in short_lower for x in ['iter', 'generator', 'yield', 'stream', 'cursor', 'scroll']):
            self.discovered_patterns['iterator'] += 1
            return ('Query', 75.0)

        # 36. Clone/Copy/Duplicate patterns
        if any(x in short_lower for x in ['clone', 'copy', 'duplicate', 'replicate', 'mirror']):
            self.discovered_patterns['clone'] += 1
            return ('Factory', 75.0)

        # 37. Connect/Disconnect/Open/Close patterns
        if any(x in short_lower for x in ['connect', 'disconnect', 'open', 'close', 'start', 'stop', 'shutdown', 'terminate']):
            self.discovered_patterns['lifecycle'] += 1
            return ('Lifecycle', 75.0)

        # 38. Wrapper/Decorator patterns
        if any(x in short_lower for x in ['wrapper', 'decorator', 'wrap', 'decorate', 'proxy']):
            self.discovered_patterns['wrapper'] += 1
            return ('Utility', 75.0)

        # 39. Nested function patterns (common)
        if any(x in short_lower for x in ['inner', 'outer', 'closure', 'nested', 'wrapped']):
            self.discovered_patterns['nested'] += 1
            return ('Internal', 70.0)

        # 40. Count/Size/Length patterns
        if any(x in short_lower for x in ['count', 'size', 'length', 'total', 'sum', 'avg', 'min', 'max']):
            self.discovered_patterns['aggregate'] += 1
            return ('Query', 75.0)

        # 41. Compare/Diff/Match patterns  
        if any(x in short_lower for x in ['compare', 'diff', 'match', 'equal', 'same', 'similar']):
            self.discovered_patterns['compare'] += 1
            return ('Asserter', 75.0)

        # 42. Split/Join/Concat patterns
        if any(x in short_lower for x in ['split', 'join', 'concat', 'append', 'prepend', 'extend']):
            self.discovered_patterns['string_ops'] += 1
            return ('Utility', 75.0)

        # 43. Wait/Sleep/Delay patterns
        if any(x in short_lower for x in ['wait', 'sleep', 'delay', 'timeout', 'pause', 'retry']):
            self.discovered_patterns['timing'] += 1
            return ('Utility', 75.0)

        # 44. Lock/Mutex/Semaphore patterns
        if any(x in short_lower for x in ['lock', 'mutex', 'semaphore', 'acquire', 'release', 'synchron']):
            self.discovered_patterns['concurrency'] += 1
            return ('Service', 75.0)

        # 45. Schedule/Job/Task/Worker patterns
        if any(x in short_lower for x in ['schedule', 'job', 'task', 'worker', 'cron', 'periodic', 'interval']):
            self.discovered_patterns['scheduler'] += 1
            return ('Command', 75.0)

        # 46. Parse/Lex/Token patterns
        if any(x in short_lower for x in ['parse', 'lex', 'token', 'ast', 'syntax', 'grammar']):
            self.discovered_patterns['parser'] += 1
            return ('Utility', 75.0)

        # 47. Format/Pretty/Style patterns
        if any(x in short_lower for x in ['format', 'pretty', 'style', 'beautify', 'minify', 'compress']):
            self.discovered_patterns['format'] += 1
            return ('Utility', 75.0)

        # 48. Version/Revision/History patterns
        if any(x in short_lower for x in ['version', 'revision', 'history', 'changelog', 'release']):
            self.discovered_patterns['version'] += 1
            return ('Query', 70.0)

        # 49. Short names (1-3 chars) are typically variables/lambdas - classify as Utility
        if len(short_lower) <= 3:
            self.discovered_patterns['short_name'] += 1
            return ('Utility', 60.0)

        # 50. CamelCase class names (starts uppercase) - check for patterns
        if short[0].isupper():
            # Classes with specific patterns
            if any(x in short_lower for x in ['exception', 'error']):
                return ('Handler', 75.0)
            if any(x in short_lower for x in ['factory', 'builder', 'creator']):
                return ('Factory', 75.0)
            if any(x in short_lower for x in ['handler', 'processor', 'worker']):
                return ('Service', 75.0)
            if any(x in short_lower for x in ['validator', 'checker', 'verifier']):
                return ('Validator', 75.0)
            if any(x in short_lower for x in ['service', 'manager', 'controller']):
                return ('Service', 75.0)
            if any(x in short_lower for x in ['repository', 'store', 'dao']):
                return ('Repository', 75.0)
            if any(x in short_lower for x in ['client', 'adapter', 'gateway']):
                return ('Mapper', 75.0)
            if any(x in short_lower for x in ['config', 'settings', 'options']):
                return ('Store', 75.0)
            # Generic class - likely DTO/Entity
            self.discovered_patterns['noun_entity'] += 1
            return ('DTO', 65.0)

        # 51. All remaining functions - classify by structure
        # If has underscores, likely internal utility
        if '_' in short_lower:
            self.discovered_patterns['underscore_func'] += 1
            return ('Utility', 60.0)

        # 52. camelCase functions (no underscore, starts lowercase)
        if short[0].islower() and '_' not in short:
            self.discovered_patterns['camelCase'] += 1
            return ('Utility', 60.0)

        # 53. Record as unknown for pattern analysis (should rarely reach here now)
        self.unknown_names.append(short_lower)
        return ('Unknown', 30.0)

    def get_pattern_report(self) -> Dict:
        """Generate report of discovered patterns."""
        # Analyze remaining unknown names for new patterns
        token_freq = Counter()
        for name in self.unknown_names:
            tokens = re.findall(r'[a-z]+', name)
            for token in tokens:
                if len(token) > 2:
                    token_freq[token] += 1

        return {
            'total_classified': sum(self.discovered_patterns.values()),
            'total_unknown': len(self.unknown_names),
            'top_patterns': self.discovered_patterns.most_common(20),
            'suggested_new_patterns': token_freq.most_common(10),
            'coverage': sum(self.discovered_patterns.values()) / 
                       (sum(self.discovered_patterns.values()) + len(self.unknown_names)) * 100
                       if (sum(self.discovered_patterns.values()) + len(self.unknown_names)) > 0 else 0
        }

def _safe_rel(repo_root: Path, file_path: str) -> str:
    try:
        p = Path(file_path).resolve()
    except Exception:
        return file_path.replace("\\", "/")
    if p.is_absolute():
        try:
            return _posix(p.relative_to(repo_root))
        except ValueError:
            return _posix(p)
    return file_path.replace("\\", "/")

def _stable_id(*parts: str) -> str:
    h = hashlib.sha1()
    for part in parts:
        h.update(part.encode("utf-8", errors="ignore"))
        h.update(b"\0")
    return h.hexdigest()[:12]

def _group_key(rel_file: str) -> str:
    p = rel_file.replace("\\", "/").lower()
    if "/domain/" in f"/{p}/" or p.startswith("domain/"):
        return "domain"
    if "/usecase/" in f"/{p}/" or "/use_case/" in f"/{p}/" or "/application/" in f"/{p}/":
        return "usecase"
    if "/infrastructure/" in f"/{p}/":
        return "infrastructure"
    if "/presentation/" in f"/{p}/" or "/controllers/" in f"/{p}/" or "/api/" in f"/{p}/":
        return "presentation"
    first = p.split("/", 1)[0].strip()
    return first or "root"

def _mermaid_id(group: str) -> str:
    safe = "".join(ch if ch.isalnum() else "_" for ch in group)
    if not safe or safe[0].isdigit():
        safe = f"g_{safe}"
    return safe

def detect_class_instantiation(nodes: List[Dict], edges: List[Dict]) -> int:
    """
    detect_class_instantiation (Task #7):
    Find edges from code instantiating a class to the class definition.
    Pattern: x = MyClass() -> invokes edge
    """
    new_edges = 0

    classes_by_name = defaultdict(list)
    for n in nodes:
        # UPDATED: Check 'kind' OR 'type' for robustness
        if n.get('kind') == 'class' or n.get('type') == 'class':
            classes_by_name[n.get('name', '')].append(n.get('id'))

    # 2. Scan all nodes for usage
    for src_node in nodes:
        body = src_node.get('body_source', '')
        if not body:
            continue

        # Naive pattern: look for ClassName()
        # (This is a heuristic, better would be AST analysis, but sticking to regex for 'light' Collider)
        import re
        for class_name, targets in classes_by_name.items():
            # Skip common/short names to avoid noise
            if len(class_name) < 4:
                continue

            # Regex: Word boundary + ClassName + (
            if re.search(r'\b' + re.escape(class_name) + r'\s*\(', body):
                for target_id in targets:
                    if target_id == src_node.get('id'):
                        continue

                    edges.append({
                        'source': src_node.get('id'),
                        'target': target_id,
                        'edge_type': 'instantiates',
                        'family': 'Dependency',
                        'inferred': True,
                        'confidence': 0.6,
                        'description': f"Class instantiation {class_name}() detected"
                    })
                    new_edges += 1

    return new_edges

def _resolve_output_dir(target: Path, output_dir: Optional[str]) -> Path:
    """Resolve the canonical output directory."""
    if output_dir:
        return Path(output_dir)
    if target.is_dir():
        return target / ".collider"
    return target.parent / ".collider"

def _find_latest_html(output_dir: Path) -> Optional[Path]:
    """Return newest output_human-readable_*.html in output_dir, if any."""
    try:
        candidates = sorted(
            output_dir.glob("output_human-readable_*.html"),
            key=lambda p: p.stat().st_mtime,
            reverse=True,
        )
    except FileNotFoundError:
        return None
    return candidates[0] if candidates else None

def _open_file(path: Path) -> bool:
    """Open a file path with the OS default handler."""
    try:
        if sys.platform == "darwin":
            subprocess.run(["open", str(path)], check=False)
        elif os.name == "nt":
            os.startfile(str(path))  # type: ignore[attr-defined]
        else:
            subprocess.run(["xdg-open", str(path)], check=False)
    except Exception:
        return False
    return True

def _manual_open_command(path: Path) -> str:
    """Return a manual open command for the current OS."""
    if sys.platform == "darwin":
        return f'open "{path}"'
    if os.name == "nt":
        return f'start \"\" \"{path}\"'
    return f'xdg-open "{path}"'

def build_file_index(nodes: List[Dict], edges: List[Dict], target_path: str = "") -> Dict[str, Any]:
    """
    Build a file-centric index of atoms for hybrid navigation.

    This bridges the atom-centric paradigm (Collider's core insight) with
    traditional file-based navigation that developers expect.

    Returns:
        {
            "file_path": {
                "atoms": [atom_indices...],
                "atom_names": ["name1", "name2"...],
                "line_range": [start, end],
                "atom_count": N,
                "imports": [...],
                "internal_edges": N,  # edges within this file
                "external_edges": N,  # edges to other files
                "purpose": "inferred purpose"
            }
        }
    """
    files_index: Dict[str, Dict[str, Any]] = {}

    # Group nodes by file
    for idx, node in enumerate(nodes):
        file_path = node.get("file_path", "")
        if not file_path:
            continue

        if file_path not in files_index:
            files_index[file_path] = {
                "atoms": [],
                "atom_names": [],
                "atom_types": [],
                "line_range": [float('inf'), 0],
                "atom_count": 0,
                "classes": [],
                "functions": [],
                "imports": [],
                "internal_edges": 0,
                "external_edges": 0,
                "purpose": ""
            }

        entry = files_index[file_path]
        entry["atoms"].append(idx)
        entry["atom_names"].append(node.get("name", ""))
        entry["atom_types"].append(node.get("type", "Unknown"))
        entry["atom_count"] += 1

        # Track line range
        line = node.get("line", 0)
        end_line = node.get("end_line", line)
        if line > 0:
            entry["line_range"][0] = min(entry["line_range"][0], line)
            entry["line_range"][1] = max(entry["line_range"][1], end_line)

        # Categorize by symbol kind
        kind = node.get("symbol_kind", "")
        name = node.get("name", "")
        if kind == "class":
            entry["classes"].append(name)
        elif kind in ("function", "method"):
            entry["functions"].append(name)

    # Compute edges (internal vs external)
    node_to_file = {idx: nodes[idx].get("file_path", "") for idx in range(len(nodes))}
    node_name_to_file = {n.get("name", ""): n.get("file_path", "") for n in nodes}

    for edge in edges:
        source = edge.get("source", "")
        target = edge.get("target", "")

        source_file = node_name_to_file.get(source, "")
        target_file = node_name_to_file.get(target, "")

        if source_file and source_file in files_index:
            if source_file == target_file:
                files_index[source_file]["internal_edges"] += 1
            else:
                files_index[source_file]["external_edges"] += 1

    # Infer file purpose from dominant atom types
    for file_path, entry in files_index.items():
        types = Counter(entry["atom_types"])
        dominant = types.most_common(1)
        if dominant:
            dom_type, count = dominant[0]
            if dom_type != "Unknown":
                entry["purpose"] = f"{dom_type}-dominant ({count}/{entry['atom_count']})"
            else:
                # Infer from file name
                fname = Path(file_path).stem.lower()
                if "test" in fname:
                    entry["purpose"] = "Test module"
                elif "util" in fname or "helper" in fname:
                    entry["purpose"] = "Utility module"
                elif "model" in fname or "entity" in fname:
                    entry["purpose"] = "Domain model"
                elif "service" in fname:
                    entry["purpose"] = "Service layer"
                elif "controller" in fname or "handler" in fname:
                    entry["purpose"] = "Interface layer"
                else:
                    entry["purpose"] = "General module"

        # Fix line_range if no lines found
        if entry["line_range"][0] == float('inf'):
            entry["line_range"] = [0, 0]

        # Clean up atom_types (don't need in output, was for computation)
        del entry["atom_types"]

    return files_index

def compute_markov_matrix(nodes: List[Dict], edges: List[Dict]) -> Dict:
    """
    Compute Markov transition matrix from call graph.
    P(A → B) = calls from A to B / total calls from A

    Also enriches edges with markov_weight for visualization.
    """
    # Build adjacency counts
    out_counts = defaultdict(lambda: defaultdict(int))
    out_totals = defaultdict(int)

    for edge in edges:
        source = edge.get('source', '')
        target = edge.get('target', '')
        if source and target:
            out_counts[source][target] += 1
            out_totals[source] += 1

    # Compute probabilities
    transitions = {}
    for source, targets in out_counts.items():
        total = out_totals[source]
        transitions[source] = {
            target: count / total
            for target, count in targets.items()
        }

    # IMPORTANT: Enrich edges with markov_weight for flow visualization
    edges_with_weight = 0
    for edge in edges:
        source = edge.get('source', '')
        target = edge.get('target', '')
        if source in transitions and target in transitions[source]:
            edge['markov_weight'] = transitions[source][target]
            edges_with_weight += 1
        else:
            edge['markov_weight'] = 0.0

    # Summary stats
    high_entropy_nodes = []
    for source, probs in transitions.items():
        if len(probs) > 5:  # Calls many things
            high_entropy_nodes.append({
                'node': source.split(':')[-1] if ':' in source else source,
                'fanout': len(probs),
                'max_prob': max(probs.values()) if probs else 0
            })

    return {
        'total_transitions': len(transitions),
        'edges_with_weight': edges_with_weight,
        'avg_fanout': sum(len(t) for t in transitions.values()) / len(transitions) if transitions else 0,
        'high_entropy_nodes': sorted(high_entropy_nodes, key=lambda x: -x['fanout'])[:10],
        'transitions': transitions  # Full transitions for frontend
    }

def compute_data_flow(nodes: List[Dict], edges: List[Dict]) -> Dict:
    """
    Analyze data flow patterns across the codebase.
    """
    # Track flow by type
    flow_by_type = defaultdict(lambda: {'in': 0, 'out': 0})

    for edge in edges:
        source = edge.get('source', '')
        target = edge.get('target', '')

        # Find source/target types
        source_type = None
        target_type = None
        for n in nodes:
            if n.get('id') == source:
                source_type = n.get('type', 'Unknown')
            if n.get('id') == target:
                target_type = n.get('type', 'Unknown')

        if source_type:
            flow_by_type[source_type]['out'] += 1
        if target_type:
            flow_by_type[target_type]['in'] += 1

    # Identify data sources and sinks
    sources = []  # High out, low in (data producers)
    sinks = []    # High in, low out (data consumers)

    for type_name, flow in flow_by_type.items():
        ratio = flow['out'] / flow['in'] if flow['in'] > 0 else flow['out']
        if ratio > 2 and flow['out'] > 10:
            sources.append({'type': type_name, 'ratio': round(ratio, 1), 'out': flow['out']})
        elif ratio < 0.5 and flow['in'] > 10:
            sinks.append({'type': type_name, 'ratio': round(ratio, 1), 'in': flow['in']})

    return {
        'flow_by_type': dict(flow_by_type),
        'data_sources': sorted(sources, key=lambda x: -x['out'])[:5],
        'data_sinks': sorted(sinks, key=lambda x: -x['in'])[:5],
        'total_flow_edges': len(edges)
    }

def infer_from_structure(node: Dict) -> Tuple[str, float, str]:
    """
    Infer type from node's own structural properties.
    Works even when no neighbors have known types.
    Returns (type, confidence, rule_name) or None.
    """
    name = node.get('name', '').split('.')[-1].lower()
    return_type = node.get('return_type', '').lower()
    params = node.get('params', [])
    docstring = node.get('docstring', '').lower()
    kind = node.get('kind', node.get('symbol_kind', ''))
    decorators = node.get('decorators', [])
    base_classes = node.get('base_classes', [])

    # Skip if already high confidence
    current_conf = node.get('role_confidence', 0)
    if current_conf >= 85:
        return None

    # -------------------------------------------------------------------------
    # STRUCTURAL RULE 1: Return type indicates Factory/Builder
    # -------------------------------------------------------------------------
    if return_type:
        # Returns a new object instance → Factory
        if any(x in return_type for x in ['new', 'create', 'make', 'build']):
            return ('Factory', 82.0, 'return_type_factory')
        # Returns a bool → likely Specification/Validator
        if return_type in ('bool', 'boolean'):
            return ('Specification', 78.0, 'return_type_bool')
        # Returns an error → Exception-related
        if 'error' in return_type or 'err' in return_type:
            return ('Exception', 78.0, 'return_type_error')

    # -------------------------------------------------------------------------
    # STRUCTURAL RULE 2: Parameter patterns
    # -------------------------------------------------------------------------
    if params:
        param_names = [p.get('name', '').lower() for p in params]
        param_types = [p.get('type', '').lower() for p in params]

        # Takes context as first param → often a Command/Query handler
        if param_names and param_names[0] in ('ctx', 'context', 'c'):
            return ('Command', 75.0, 'context_first_param')

        # Takes request/response → Controller/Handler
        if any(p in param_names for p in ['request', 'req', 'response', 'resp', 'w', 'r']):
            return ('Controller', 78.0, 'http_params')

        # Takes reader/writer → IO utility
        if any('reader' in p or 'writer' in p for p in param_types):
            return ('Utility', 75.0, 'io_params')

    # -------------------------------------------------------------------------
    # STRUCTURAL RULE 3: Docstring patterns
    # -------------------------------------------------------------------------
    if docstring:
        if any(x in docstring for x in ['test', 'verify', 'assert']):
            return ('Test', 82.0, 'docstring_test')
        if any(x in docstring for x in ['create', 'build', 'construct', 'generate']):
            return ('Factory', 78.0, 'docstring_factory')
        if any(x in docstring for x in ['validate', 'check', 'ensure']):
            return ('Validator', 78.0, 'docstring_validator')
        if any(x in docstring for x in ['parse', 'decode', 'unmarshal']):
            return ('Query', 78.0, 'docstring_parser')
        if any(x in docstring for x in ['write', 'save', 'store', 'persist']):
            return ('Command', 78.0, 'docstring_persist')

    # -------------------------------------------------------------------------
    # STRUCTURAL RULE 4: High complexity → likely Service
    # -------------------------------------------------------------------------
    complexity = node.get('complexity', 0)
    if complexity > 20:
        return ('Service', 72.0, 'high_complexity')

    # -------------------------------------------------------------------------
    # STRUCTURAL RULE 5: Zero out-degree leaf → likely DTO/ValueObject
    # -------------------------------------------------------------------------
    if kind == 'class' and node.get('out_degree', 0) == 0:
        return ('DTO', 72.0, 'leaf_class')

    return None

def _get_language(lang: str):
    """Lazy load language module."""
    global _languages
    if lang not in _languages:
        if lang == 'python':
            import tree_sitter_python
            _languages[lang] = tree_sitter_python.language()
        elif lang in ('javascript', 'typescript'):
            import tree_sitter_javascript
            _languages[lang] = tree_sitter_javascript.language()
        else:
            return None
    return _languages[lang]

def _analyze_python_data_flow(tree, source: bytes, graph: DataFlowGraph):
    """Analyze Python data flow using AST traversal."""
    # Track variables declared global/nonlocal for is_global_write detection
    global_vars: set = set()

    def visit_node(node):
        node_type = node.type

        # Regular assignment: x = value
        if node_type == 'assignment':
            _process_python_assignment(node, source, graph, global_vars)

        # Augmented assignment: x += value (mutation)
        elif node_type == 'augmented_assignment':
            _process_python_augmented_assignment(node, source, graph, global_vars)

        # Attribute assignment: obj.attr = value (mutation)
        elif node_type == 'assignment' and _is_attribute_target(node):
            # Already handled in _process_python_assignment
            pass

        # Global/nonlocal declarations
        elif node_type in ('global_statement', 'nonlocal_statement'):
            _process_global_statement(node, source, graph, global_vars)

        # Function calls that may have side effects or mutate objects
        elif node_type == 'call':
            _check_side_effect_call(node, source, graph, 'python')
            _check_mutating_method_call(node, source, graph, 'python')

        # Delete statement (mutation)
        elif node_type == 'delete_statement':
            _process_delete_statement(node, source, graph)

        # Recurse
        for child in node.children:
            visit_node(child)

    visit_node(tree.root_node)

def _analyze_js_data_flow(tree, source: bytes, graph: DataFlowGraph):
    """Analyze JavaScript/TypeScript data flow."""

    def visit_node(node):
        node_type = node.type

        # Variable declaration with initializer
        if node_type == 'variable_declarator':
            _process_js_declarator(node, source, graph)

        # Assignment expression
        elif node_type == 'assignment_expression':
            _process_js_assignment(node, source, graph)

        # Augmented assignment
        elif node_type == 'augmented_assignment_expression':
            _process_js_augmented_assignment(node, source, graph)

        # Update expression (++, --)
        elif node_type == 'update_expression':
            _process_js_update(node, source, graph)

        # Function calls
        elif node_type == 'call_expression':
            _check_side_effect_call(node, source, graph, 'javascript')
            _check_mutating_method_call(node, source, graph, 'javascript')

        # Recurse
        for child in node.children:
            visit_node(child)

    visit_node(tree.root_node)

def _get_python_target_name(node, source: bytes) -> Tuple[str, bool]:
    """Get target name and whether it's an attribute write."""
    if node.type == 'identifier':
        name = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return name, False
    elif node.type == 'attribute':
        # Get full attribute path: obj.attr
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, True
    elif node.type == 'subscript':
        # Array/dict indexing: arr[i]
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, True
    elif node.type == 'tuple_pattern' or node.type == 'list_pattern':
        # Destructuring: a, b = ...
        return '<destructured>', False
    else:
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, False

def _is_attribute_target(node) -> bool:
    """Check if assignment target is an attribute access."""
    left = node.child_by_field_name('left')
    if left and left.type in ('attribute', 'subscript', 'member_expression', 'subscript_expression'):
        return True
    return False

def _extract_referenced_names(node, source: bytes) -> List[str]:
    """Extract all identifier names referenced in a node."""
    if node is None:
        return []

    names = []

    def collect_names(n):
        if n.type == 'identifier':
            name = source[n.start_byte:n.end_byte].decode('utf8', errors='replace')
            names.append(name)
        for child in n.children:
            collect_names(child)

    collect_names(node)
    return names

def _check_side_effect_call(node, source: bytes, graph: DataFlowGraph, language: str):
    """Check if a function call has side effects."""
    indicators = SIDE_EFFECT_FUNCTIONS.get(language, {})

    # Get the function name being called
    func_node = node.child_by_field_name('function')
    if not func_node:
        for child in node.children:
            if child.type in ('identifier', 'attribute', 'member_expression'):
                func_node = child
                break

    if not func_node:
        return

    func_name = source[func_node.start_byte:func_node.end_byte].decode('utf8', errors='replace')

    # Check against known side effect indicators
    for effect_kind, names in indicators.items():
        for indicator in names:
            if indicator in func_name or func_name == indicator:
                effect = SideEffect(
                    kind=effect_kind,
                    name=func_name,
                    line=node.start_point[0] + 1,
                    evidence=f"Call to {func_name}",
                )
                graph.side_effects.append(effect)
                return

def _check_mutating_method_call(node, source: bytes, graph: DataFlowGraph, language: str):
    """
    Check if a method call mutates its receiver object.

    Detects patterns like: list.append(), dict.update(), set.add()
    These are recorded as mutations even though they don't use assignment syntax.
    """
    mutating_methods = MUTATING_METHODS.get(language, set())
    if not mutating_methods:
        return

    # Get the function/method being called
    func_node = node.child_by_field_name('function')
    if not func_node:
        for child in node.children:
            if child.type in ('attribute', 'member_expression'):
                func_node = child
                break

    if not func_node:
        return

    # Check if it's a method call (attribute access)
    if func_node.type not in ('attribute', 'member_expression'):
        return

    # Get the method name (the last part of the attribute chain)
    method_name = None
    if func_node.type == 'attribute':
        # Python: obj.method
        attr_node = func_node.child_by_field_name('attribute')
        if attr_node:
            method_name = source[attr_node.start_byte:attr_node.end_byte].decode('utf8', errors='replace')
    elif func_node.type == 'member_expression':
        # JavaScript: obj.method
        prop_node = func_node.child_by_field_name('property')
        if prop_node:
            method_name = source[prop_node.start_byte:prop_node.end_byte].decode('utf8', errors='replace')

    if not method_name:
        # Fallback: try to extract from children
        for child in func_node.children:
            if child.type == 'identifier' and child != func_node.children[0]:
                method_name = source[child.start_byte:child.end_byte].decode('utf8', errors='replace')
                break

    if method_name and method_name in mutating_methods:
        # Get the receiver object name
        receiver_name = '<object>'
        if func_node.type == 'attribute':
            obj_node = func_node.child_by_field_name('object')
            if obj_node:
                receiver_name = source[obj_node.start_byte:obj_node.end_byte].decode('utf8', errors='replace')
        elif func_node.type == 'member_expression':
            obj_node = func_node.child_by_field_name('object')
            if obj_node:
                receiver_name = source[obj_node.start_byte:obj_node.end_byte].decode('utf8', errors='replace')

        # Record as a mutation
        assignment = Assignment(
            target_name=receiver_name,
            target_node_id=func_node.id,
            source_names=[],
            start_line=node.start_point[0] + 1,
            start_byte=node.start_byte,
            end_byte=node.end_byte,
            is_mutation=True,
            is_attribute_write=True,  # Method mutation is similar to attribute write
        )

        graph.assignments.append(assignment)
        graph.mutations.append(assignment)

def _count_mutation_types(graph: DataFlowGraph) -> Dict[str, int]:
    """Count mutations by type."""
    counts = {'attribute_write': 0, 'augmented': 0, 'other': 0}
    for m in graph.mutations:
        if m.is_attribute_write:
            counts['attribute_write'] += 1
        elif len(m.source_names) > 0 and m.target_name in m.source_names:
            counts['augmented'] += 1
        else:
            counts['other'] += 1
    return counts

def _count_side_effect_types(graph: DataFlowGraph) -> Dict[str, int]:
    """Count side effects by type."""
    counts = {}
    for effect in graph.side_effects:
        counts[effect.kind] = counts.get(effect.kind, 0) + 1
    return counts

def analyze_function_purity(func_node, source: bytes, language: str) -> Tuple[float, Dict]:
    """
    Analyze purity of a single function.

    Args:
        func_node: tree-sitter node for the function
        source: Full source code as bytes
        language: Language name

    Returns:
        Tuple of (purity_score, factors_dict)
    """
    # Create a mini data flow graph for just this function
    graph = DataFlowGraph(file_path='', language=language)

    if language == 'python':
        def visit(node):
            if node.type == 'assignment':
                _process_python_assignment(node, source, graph)
            elif node.type == 'augmented_assignment':
                _process_python_augmented_assignment(node, source, graph)
            elif node.type == 'call':
                _check_side_effect_call(node, source, graph, 'python')
            for child in node.children:
                visit(child)
        visit(func_node)

    elif language in ('javascript', 'typescript'):
        def visit(node):
            if node.type == 'assignment_expression':
                _process_js_assignment(node, source, graph)
            elif node.type == 'augmented_assignment_expression':
                _process_js_augmented_assignment(node, source, graph)
            elif node.type == 'update_expression':
                _process_js_update(node, source, graph)
            elif node.type == 'call_expression':
                _check_side_effect_call(node, source, graph, 'javascript')
            for child in node.children:
                visit(child)
        visit(func_node)

    graph.pure_score = calculate_purity(graph)
    return graph.pure_score, get_purity_factors(graph)

class Counter:
    def increment(self):
        self.count += 1     # mutation (attribute write)

def load_yaml_atoms(yaml_path: Path) -> List[Dict]:
    """Load atoms from a YAML file."""
    if not yaml_path.exists():
        return []

    with open(yaml_path, 'r', encoding='utf-8') as f:
        data = yaml.safe_load(f)

    return data.get('atoms', [])

def load_json_atoms(json_path: Path) -> Dict:
    """Load atoms from atoms.json."""
    if not json_path.exists():
        return {}

    with open(json_path, 'r', encoding='utf-8') as f:
        data = json.load(f)

    return data

def infer_phase_family(atom_id: str) -> tuple:
    """Infer phase and family from atom ID pattern."""
    # For YAML atoms like C1_IntLiteral
    if atom_id.startswith('C1_'):
        return ('DATA', 'Literals') if 'Literal' in atom_id else ('LOGIC', 'Expressions')
    if atom_id.startswith('C2_'):
        return ('LOGIC', 'Statements')
    if atom_id.startswith('C3_'):
        return ('ORGANIZATION', 'Structures')

    # For JSON atoms like DAT.BYT.A
    if atom_id.startswith('DAT'):
        return ('DATA', 'Primitives')
    if atom_id.startswith('LOG'):
        return ('LOGIC', 'Functions')
    if atom_id.startswith('ORG'):
        return ('ORGANIZATION', 'Aggregates')
    if atom_id.startswith('EXE'):
        return ('EXECUTION', 'Handlers')
    if atom_id.startswith('SYS'):
        return ('EXECUTION', 'System')

    return ('LOGIC', 'Unknown')

def _infer_mined_phase_family(ecosystem: str, category: str) -> tuple:
    """Infer phase and family for mined T2 atoms based on ecosystem and category."""
    ecosystem = ecosystem.lower()
    category = category.lower()

    # Security-related atoms
    if 'security' in category or 'sec' in category:
        return ('SECURITY', ecosystem.capitalize())

    # Web frameworks
    if ecosystem in ('django', 'flask', 'fastapi', 'express', 'rails', 'spring', 'laravel'):
        return ('WEB', ecosystem.capitalize())

    # Frontend frameworks
    if ecosystem in ('react', 'vue', 'angular', 'svelte'):
        return ('FRONTEND', ecosystem.capitalize())

    # Cloud/Infrastructure
    if ecosystem in ('aws', 'aws-lambda', 'gcp', 'azure', 'terraform', 'kubernetes', 'docker'):
        return ('CLOUD', ecosystem.capitalize())

    # Machine Learning
    if ecosystem in ('tensorflow', 'pytorch', 'keras', 'scikit-learn'):
        return ('ML', ecosystem.capitalize())

    # Languages
    if ecosystem in ('python', 'javascript', 'typescript', 'java', 'go', 'ruby', 'rust', 'php'):
        return ('LANGUAGE', ecosystem.capitalize())

    # Default
    return ('ECOSYSTEM', ecosystem.capitalize() if ecosystem else 'General')

def build_unified_taxonomy(patterns_dir: Path = None) -> Dict:
    """
    Build unified taxonomy from all atom sources.

    Returns structure compatible with atom_classifier.py:
    {
        "phases": {
            "DATA": {
                "families": {
                    "Literals": {
                        "atoms": [{"id": "...", "name": "..."}]
                    }
                }
            }
        },
        "atoms": {...},  # flat lookup
        "mappings": {...},  # AST mappings
        "tier_info": {...}  # tier metadata
    }
    """
    if patterns_dir is None:
        patterns_dir = Path(__file__).parent.parent / "patterns"

    # Initialize structure
    taxonomy = {
        "version": "2.0.0",
        "phases": {},
        "atoms": {},
        "mappings": {},
        "tier_info": {
            "T0": {"count": 0, "source": "ATOMS_TIER0_CORE.yaml"},
            "T1": {"count": 0, "source": "ATOMS_TIER1_STDLIB.yaml"},
            "T2": {"count": 0, "source": "ATOMS_TIER2_ECOSYSTEM.yaml"},
            "base": {"count": 0, "source": "atoms.json"}
        }
    }

    # Load base atoms.json
    base_json = load_json_atoms(patterns_dir / "atoms.json")
    if "atoms" in base_json:
        for atom_id, atom_data in base_json["atoms"].items():
            phase, family = infer_phase_family(atom_id)
            _add_atom(taxonomy, phase, family, {
                "id": atom_id,
                "name": atom_data.get("name", atom_id),
                "description": atom_data.get("description", ""),
                "tier": "base"
            })
            taxonomy["atoms"][atom_id] = atom_data
            taxonomy["tier_info"]["base"]["count"] += 1

    # Copy AST mappings
    if "mappings" in base_json:
        taxonomy["mappings"] = base_json["mappings"]

    # Load T0 atoms
    t0_atoms = load_yaml_atoms(patterns_dir / "ATOMS_TIER0_CORE.yaml")
    for atom in t0_atoms:
        atom_id = atom.get("id", "")
        phase, family = infer_phase_family(atom_id)
        _add_atom(taxonomy, phase, family, {
            "id": atom_id,
            "name": atom.get("name", atom_id),
            "symbol": atom.get("symbol", ""),
            "dimensions": atom.get("default_dimensions", []),
            "tier": "T0"
        })
        taxonomy["atoms"][atom_id] = atom
        taxonomy["tier_info"]["T0"]["count"] += 1

    # Load T1 atoms
    t1_atoms = load_yaml_atoms(patterns_dir / "ATOMS_TIER1_STDLIB.yaml")
    for atom in t1_atoms:
        atom_id = atom.get("id", "")
        phase, family = infer_phase_family(atom_id)
        _add_atom(taxonomy, phase, family, {
            "id": atom_id,
            "name": atom.get("name", atom_id),
            "symbol": atom.get("symbol", ""),
            "tier": "T1"
        })
        taxonomy["atoms"][atom_id] = atom
        taxonomy["tier_info"]["T1"]["count"] += 1

    # Load T2 atoms (original)
    t2_atoms = load_yaml_atoms(patterns_dir / "ATOMS_TIER2_ECOSYSTEM.yaml")
    for atom in t2_atoms:
        atom_id = atom.get("id", "")
        phase, family = infer_phase_family(atom_id)
        _add_atom(taxonomy, phase, family, {
            "id": atom_id,
            "name": atom.get("name", atom_id),
            "symbol": atom.get("symbol", ""),
            "tier": "T2"
        })
        taxonomy["atoms"][atom_id] = atom
        taxonomy["tier_info"]["T2"]["count"] += 1

    # Load mined T2 atoms from t2_mined directory
    t2_mined_dir = patterns_dir / "t2_mined"
    if t2_mined_dir.exists():
        mined_count = 0
        seen_ids = set(taxonomy["atoms"].keys())  # Avoid duplicates
        for yaml_file in sorted(t2_mined_dir.glob("ATOMS_T2_*.yaml")):
            mined_atoms = load_yaml_atoms(yaml_file)
            for atom in mined_atoms:
                atom_id = atom.get("id", "")
                if atom_id in seen_ids:
                    continue  # Skip duplicates
                seen_ids.add(atom_id)

                # Infer phase and family for mined atoms
                ecosystem = atom.get("ecosystem", "")
                category = atom.get("category", "")
                phase, family = _infer_mined_phase_family(ecosystem, category)

                _add_atom(taxonomy, phase, family, {
                    "id": atom_id,
                    "name": atom.get("name", atom_id),
                    "ecosystem": ecosystem,
                    "category": category,
                    "tier": "T2"
                })
                taxonomy["atoms"][atom_id] = atom
                mined_count += 1

        taxonomy["tier_info"]["T2_mined"] = {
            "count": mined_count,
            "source": "t2_mined/*.yaml"
        }

    return taxonomy

def _add_atom(taxonomy: Dict, phase: str, family: str, atom: Dict):
    """Add atom to taxonomy structure."""
    if phase not in taxonomy["phases"]:
        taxonomy["phases"][phase] = {"families": {}}

    if family not in taxonomy["phases"][phase]["families"]:
        taxonomy["phases"][phase]["families"][family] = {"atoms": []}

    taxonomy["phases"][phase]["families"][family]["atoms"].append(atom)

def get_unified_taxonomy() -> Dict:
    """Get or build unified taxonomy (cached)."""
    if not hasattr(get_unified_taxonomy, '_cache'):
        get_unified_taxonomy._cache = build_unified_taxonomy()
    return get_unified_taxonomy._cache

