def validate_node(node: Dict[str, Any]) -> Tuple[List[str], List[str]]:
    """Validate a node dict. Returns (errors, warnings)."""
    errors: List[str] = []
    warnings: List[str] = []

    # Required fields
    if not node.get('id'):
        errors.append("Node missing required 'id' field")
    else:
        node_id = str(node["id"])
        if ID_CANONICAL_PATTERN.match(node_id):
            pass
        elif ID_LEGACY_PATTERN.match(node_id):
            warnings.append(f"Legacy id format: {node_id}")
        else:
            warnings.append(f"Non-canonical id format: {node_id}")

    if not node.get('name'):
        errors.append("Node missing required 'name' field")

    # Confidence range (canonical: 0.0-1.0)
    for key, value in node.items():
        if not is_confidence_key(key):
            continue
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            errors.append(f"{key} not numeric: {value}")
            continue
        if not 0.0 <= numeric <= 1.0:
            errors.append(f"{key} out of range (0.0-1.0): {value}")

    atom = node.get('atom')
    if atom and isinstance(atom, str) and not ATOM_PATTERN.match(atom):
        warnings.append(f"Atom format mismatch: {atom}")

    return errors, warnings

def validate_edge(edge: Dict[str, Any], node_ids: Set[str]) -> Tuple[List[str], List[str]]:
    """Validate an edge dict. Returns (errors, warnings)."""
    errors: List[str] = []
    warnings: List[str] = []

    if not edge.get('source'):
        errors.append("Edge missing 'source'")
    elif edge['source'] not in node_ids:
        errors.append(f"Edge source not in graph: {edge['source'][:50]}...")

    if not edge.get('target'):
        errors.append("Edge missing 'target'")
    # Target may be external - don't error

    for key, value in edge.items():
        if not is_confidence_key(key):
            continue
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            errors.append(f"Edge {key} not numeric: {value}")
            continue
        if not 0.0 <= numeric <= 1.0:
            errors.append(f"Edge {key} out of range 0.0-1.0: {value}")

    return errors, warnings

def find_communities_louvain(G: "nx.DiGraph") -> dict[int, list[str]]:
    """
    Detect communities using Louvain algorithm (fallback).

    Returns dict: community_id -> list of node IDs.
    """
    if community_louvain is None:
        # Ultimate fallback: use connected components
        undirected = G.to_undirected()
        communities = {}
        for i, component in enumerate(nx.connected_components(undirected)):
            communities[i] = list(component)
        return communities

    # Louvain works on undirected graphs
    undirected = G.to_undirected()
    partition = community_louvain.best_partition(undirected)

    # Invert: community_id -> [nodes]
    communities = {}
    for node, comm_id in partition.items():
        if comm_id not in communities:
            communities[comm_id] = []
        communities[comm_id].append(node)

    return communities

def find_communities(G: "nx.DiGraph", algorithm: str = "auto") -> dict[int, list[str]]:
    """
    Detect communities using the best available algorithm.

    Args:
        G: NetworkX directed graph
        algorithm: "leiden", "louvain", or "auto" (default, uses Leiden if available)

    Returns dict: community_id -> list of node IDs.
    """
    if algorithm == "leiden" or (algorithm == "auto" and HAS_LEIDEN):
        return find_communities_leiden(G)
    else:
        return find_communities_louvain(G)

def shortest_path(G: "nx.DiGraph", source: str, target: str) -> list[str]:
    """
    Find shortest path between two nodes.

    Accepts either full ID or just function name (will search).
    """
    if nx is None:
        return []

    # Resolve partial names to full IDs
    def resolve(name):
        if name in G.nodes:
            return name
        for node_id in G.nodes:
            if f"|{name}|" in node_id or node_id.endswith(f"|{name}"):
                return node_id
        # Try name attribute
        for node_id, info in G.nodes(data=True):
            if info.get("name") == name:
                return node_id
        return None

    src = resolve(source)
    tgt = resolve(target)

    if not src or not tgt:
        return []

    try:
        return nx.shortest_path(G, src, tgt)
    except nx.NetworkXNoPath:
        return []

