def capture_node_fields(nodes: Dict[str, Dict]) -> Set[str]:
    """Get all field names present across nodes."""
    fields = set()
    for node in nodes.values():
        fields.update(node.keys())
    return fields

def get_sample_node(nodes: Dict[str, Dict], prefer_enriched: bool = True) -> Optional[Dict]:
    """
    Get a representative sample node for preview.

    Prefers nodes with more fields (more enriched) if prefer_enriched=True.
    """
    if not nodes:
        return None

    if prefer_enriched:
        # Sort by number of fields, take the richest
        sorted_nodes = sorted(
            nodes.values(),
            key=lambda n: len(n),
            reverse=True
        )
        node = sorted_nodes[0]
    else:
        # Just take first
        node = next(iter(nodes.values()))

    # Return a cleaned copy (truncate large fields)
    cleaned = {}
    for k, v in node.items():
        if k == 'body_source' and isinstance(v, str) and len(v) > 200:
            cleaned[k] = v[:200] + f"... ({len(v)} chars)"
        elif isinstance(v, str) and len(v) > 500:
            cleaned[k] = v[:500] + "..."
        else:
            cleaned[k] = v

    return cleaned

def load_json(path: Path) -> Any:
    """Load JSON file safely."""
    return json.loads(path.read_text(encoding="utf-8"))

def safe_get(obj: Any, dotted_path: str, default: Any = None) -> Any:
    """Get nested value using dot notation."""
    cur = obj
    for part in dotted_path.split("."):
        if isinstance(cur, dict) and part in cur:
            cur = cur[part]
        elif isinstance(cur, list) and part.isdigit():
            idx = int(part)
            if 0 <= idx < len(cur):
                cur = cur[idx]
            else:
                return default
        else:
            return default
    return cur

def first_path(obj: Any, paths: List[str], default: Any = None) -> Any:
    """Try multiple paths, return first non-None value."""
    for p in paths:
        v = safe_get(obj, p)
        if v is not None:
            return v
    return default

class OverallUnderstandingQuery:
    """
    Executes the overall understanding query on analysis output.

    Produces:
    - Provenance section (was this run valid?)
    - Core metrics (what's in the codome?)
    - Dark matter analysis (invisible dependencies)
    - Confidence analysis (how certain are we?)
    - Quality gates (did we meet thresholds?)
    - Recommendations (what to do next?)
    """

    def __init__(self, unified: Dict[str, Any], manifest: Optional[Dict[str, Any]] = None):
        self.unified = unified
        self.manifest = manifest or {}
        self.metrics: Dict[str, Any] = {}
        self.issues: List[Dict[str, Any]] = []

    def execute(self) -> Dict[str, Any]:
        """Run the complete query."""
        self._extract_metrics()
        self._run_quality_gates()

        return {
            "query_id": "overall_understanding_v1",
            "generated_at_utc": datetime.now(timezone.utc).isoformat(),
            "provenance": self._build_provenance(),
            "metrics": self.metrics,
            "dark_matter": self._analyze_dark_matter(),
            "confidence": self._analyze_confidence(),
            "quality_gates": self._build_quality_gates(),
            "recommendations": self._generate_recommendations(),
            "issues": self.issues,
        }

    def _extract_metrics(self) -> None:
        """Extract core metrics from unified analysis."""
        u = self.unified

        # Core scale
        by_kind = first_path(u, ["classification.by_kind"], {})
        self.metrics["total_nodes"] = sum(by_kind.values()) if isinstance(by_kind, dict) else 0
        self.metrics["total_edges"] = first_path(u, [
            "graph.total_edges",
            "codome.total_edges",
            "analytics.edges_count"
        ], len(first_path(u, ["edges"], [])))

        # Kind distribution
        self.metrics["by_kind"] = by_kind

        # Role distribution
        self.metrics["by_role"] = first_path(u, ["classification.by_role"], {})

        # Confidence distribution
        self.metrics["by_confidence"] = first_path(u, ["classification.by_confidence"], {})

        # Dark matter
        codome_boundaries = first_path(u, ["codome_boundaries.boundary_nodes"], [])
        self.metrics["dark_edge_count"] = sum(
            n.get("out_degree", 0) for n in codome_boundaries
            if isinstance(n, dict)
        )
        self.metrics["dark_by_source"] = {}
        for bn in codome_boundaries:
            if isinstance(bn, dict):
                source = bn.get("codome_source", bn.get("name", "unknown"))
                self.metrics["dark_by_source"][source] = bn.get("out_degree", 0)

        # Entropy (dimension information content)
        self.metrics["entropy"] = first_path(u, ["analytics.entropy"], {})

    def _run_quality_gates(self) -> None:
        """Check quality gate thresholds."""
        total = self.metrics.get("total_nodes", 0)
        edges = self.metrics.get("total_edges", 0)

        # Gate 1: Must have nodes
        if total == 0:
            self.issues.append({
                "gate": "has_nodes",
                "severity": "error",
                "message": "No nodes found in analysis"
            })

        # Gate 2: Must have edges (unless very small codebase)
        if edges == 0 and total > 10:
            self.issues.append({
                "gate": "has_edges",
                "severity": "warning",
                "message": f"No edges found for {total} nodes"
            })

        # Gate 3: Confidence distribution should be reasonable
        by_conf = self.metrics.get("by_confidence", {})
        if by_conf:
            low = by_conf.get("low", 0)
            total_conf = sum(by_conf.values())
            if total_conf > 0 and low / total_conf > 0.5:
                self.issues.append({
                    "gate": "confidence_acceptable",
                    "severity": "warning",
                    "message": f"Over 50% of nodes have low confidence ({low}/{total_conf})"
                })

        # Gate 4: Dark ratio should be sane (0-100%)
        dark = self.metrics.get("dark_edge_count", 0)
        if edges > 0:
            ratio = dark / edges
            if ratio > 1.0:
                self.issues.append({
                    "gate": "dark_ratio_sane",
                    "severity": "error",
                    "message": f"Dark ratio {ratio:.2f} > 1.0 (impossible)"
                })

    def _build_provenance(self) -> Dict[str, Any]:
        """Build provenance section from manifest."""
        m = self.manifest
        return {
            "run_id": safe_get(m, "input.git_commit", "unknown"),
            "schema_version": safe_get(m, "schema_version", "unknown"),
            "git_commit": safe_get(m, "input.git_commit"),
            "git_dirty": safe_get(m, "input.git_dirty", True),
            "collider_version": safe_get(m, "pipeline.collider_version", "unknown"),
            "merkle_root": safe_get(m, "checksums.merkle_root"),
            "generated_at": safe_get(m, "generated_at_utc"),
        }

    def _analyze_dark_matter(self) -> Dict[str, Any]:
        """Analyze dark matter (invisible dependencies)."""
        total_edges = self.metrics.get("total_edges", 0)
        dark_edges = self.metrics.get("dark_edge_count", 0)
        dark_by_source = self.metrics.get("dark_by_source", {})

        ratio = dark_edges / total_edges if total_edges > 0 else 0

        # Signature analysis
        signature = []
        if dark_edges > 0:
            for source, count in sorted(dark_by_source.items(), key=lambda x: -x[1]):
                pct = count / dark_edges
                signature.append({
                    "source": source,
                    "count": count,
                    "percent": round(pct * 100, 1),
                })

        # Heuristic predictions
        predictions = []
        if ratio >= 0.20:
            predictions.append("High Dark Matter (>=20%): heavy framework/test/runtime influence")
        elif ratio >= 0.10:
            predictions.append("Moderate Dark Matter (10-20%): boundaries should be theorized")
        else:
            predictions.append("Low Dark Matter (<10%): most dependencies observable in code")

        # Source-specific predictions
        test_pct = dark_by_source.get("test_entry", 0) / dark_edges if dark_edges else 0
        if test_pct >= 0.30:
            predictions.append("TestFramework dominates: likely high test harness influence")

        framework_pct = dark_by_source.get("framework_managed", 0) / dark_edges if dark_edges else 0
        if framework_pct >= 0.20:
            predictions.append("Heavy framework coupling: DI/decorators create invisible edges")

        return {
            "total_dark_edges": dark_edges,
            "dark_ratio": round(ratio, 4),
            "signature": signature,
            "predictions": predictions,
        }

    def _analyze_confidence(self) -> Dict[str, Any]:
        """Analyze confidence distribution."""
        by_conf = self.metrics.get("by_confidence", {})

        if not by_conf:
            return {"status": "no_confidence_data"}

        total = sum(by_conf.values())
        distribution = {}
        for level, count in by_conf.items():
            distribution[level] = {
                "count": count,
                "percent": round(count / total * 100, 1) if total > 0 else 0
            }

        # Compute overall confidence score (weighted average)
        weights = {"high": 1.0, "medium": 0.6, "low": 0.2}
        weighted_sum = sum(by_conf.get(k, 0) * v for k, v in weights.items())
        overall = weighted_sum / total if total > 0 else 0

        # Recommendations based on confidence
        recommendations = []
        low_pct = distribution.get("low", {}).get("percent", 0)
        if low_pct > 40:
            recommendations.append("High uncertainty: 40%+ nodes have low confidence. Extend classifiers.")
        elif low_pct > 25:
            recommendations.append("Moderate uncertainty: 25-40% low confidence. Review edge cases.")

        return {
            "distribution": distribution,
            "overall_score": round(overall, 3),
            "recommendations": recommendations,
        }

    def _build_quality_gates(self) -> Dict[str, Any]:
        """Build quality gates summary."""
        errors = [i for i in self.issues if i.get("severity") == "error"]
        warnings = [i for i in self.issues if i.get("severity") == "warning"]

        return {
            "passed": len(errors) == 0,
            "error_count": len(errors),
            "warning_count": len(warnings),
            "gates": self.issues,
        }

    def _generate_recommendations(self) -> List[Dict[str, Any]]:
        """Generate actionable recommendations."""
        recs = []

        # From dark matter analysis
        dark = self._analyze_dark_matter()
        if dark.get("dark_ratio", 0) >= 0.10:
            recs.append({
                "priority": "high",
                "category": "theory",
                "title": "Formalize Dark Matter",
                "description": f"Dark ratio {dark['dark_ratio']:.1%} is significant. "
                               "Codome boundaries should be theoretically grounded.",
                "action": "Implement Proposal 2: Dark Matter as first-class theoretical object"
            })

        # From confidence analysis
        conf = self._analyze_confidence()
        if conf.get("overall_score", 1.0) < 0.7:
            recs.append({
                "priority": "high",
                "category": "theory",
                "title": "Model Uncertainty Explicitly",
                "description": f"Overall confidence {conf.get('overall_score', 0):.1%} is low. "
                               "Classification uncertainty should be modeled, not hidden.",
                "action": "Implement Proposal 3: Confidence as meta-dimension"
            })

        # From quality gates
        if self.issues:
            for issue in self.issues:
                if issue.get("severity") == "error":
                    recs.append({
                        "priority": "critical",
                        "category": "data_quality",
                        "title": f"Fix: {issue.get('gate', 'unknown')}",
                        "description": issue.get("message", ""),
                        "action": "Investigate and fix data quality issue"
                    })

        return recs

class QueryLoader:
    """Loads and caches tree-sitter query files (.scm)."""

    # Standard query types (including dimension classifiers)
    QUERY_TYPES = ['symbols', 'locals', 'highlights', 'injections', 'patterns',
                   'boundary', 'state', 'lifecycle', 'data_flow', 'imports', 'roles']

    # Language aliases (multiple extensions map to same queries)
    LANGUAGE_ALIASES = {
        'tsx': 'typescript',
        'jsx': 'javascript',
    }

    # Language inheritance (child inherits from parent if missing)
    LANGUAGE_INHERITANCE = {
        'typescript': 'javascript',
        'tsx': 'javascript',
    }

    def __init__(self, queries_dir: Optional[Path] = None):
        if queries_dir is None:
            # Default to queries/ directory (same as this file)
            self.queries_dir = Path(__file__).parent
        else:
            self.queries_dir = Path(queries_dir)

        self._cache: Dict[str, QueryBundle] = {}
        self._validation_errors: Dict[str, List[str]] = {}

    def _resolve_language(self, language: str) -> str:
        """Resolve language aliases to canonical names."""
        return self.LANGUAGE_ALIASES.get(language, language)

    def _load_query_file(self, language: str, query_type: str) -> Optional[str]:
        """Load a single .scm file, returning None if not found."""
        # Try language-specific file first
        lang_dir = self.queries_dir / language
        query_path = lang_dir / f"{query_type}.scm"

        if query_path.exists():
            try:
                return query_path.read_text(encoding='utf-8')
            except Exception as e:
                self._log_error(language, f"Failed to read {query_path}: {e}")
                return None

        # Try inherited language
        parent = self.LANGUAGE_INHERITANCE.get(language)
        if parent:
            return self._load_query_file(parent, query_type)

        # Try fallback
        if language != '_fallback':
            fallback_path = self.queries_dir / '_fallback' / f"{query_type}.scm"
            if fallback_path.exists():
                try:
                    return fallback_path.read_text(encoding='utf-8')
                except Exception as e:
                    self._log_error(language, f"Failed to read fallback {fallback_path}: {e}")
                    return None

        return None

    def _log_error(self, language: str, error: str):
        """Log a validation error for a language."""
        if language not in self._validation_errors:
            self._validation_errors[language] = []
        self._validation_errors[language].append(error)

    def load_bundle(self, language: str) -> QueryBundle:
        """Load all queries for a language as a bundle."""
        canonical = self._resolve_language(language)

        if canonical in self._cache:
            return self._cache[canonical]

        raw_files = {}
        for query_type in self.QUERY_TYPES:
            content = self._load_query_file(canonical, query_type)
            if content:
                raw_files[query_type] = content

        bundle = QueryBundle(
            language=canonical,
            symbols=raw_files.get('symbols'),
            locals=raw_files.get('locals'),
            highlights=raw_files.get('highlights'),
            injections=raw_files.get('injections'),
            patterns=raw_files.get('patterns'),
            imports=raw_files.get('imports'),
            boundary=raw_files.get('boundary'),
            state=raw_files.get('state'),
            lifecycle=raw_files.get('lifecycle'),
            data_flow=raw_files.get('data_flow'),
            roles=raw_files.get('roles'),
            _raw_files=raw_files,
        )

        self._cache[canonical] = bundle
        return bundle

    def load_query(self, language: str, query_type: str) -> Optional[str]:
        """Load a specific query for a language."""
        bundle = self.load_bundle(language)
        return bundle.get_query(query_type)

    def list_languages(self) -> List[str]:
        """List available languages (directories with .scm files)."""
        languages = []
        for item in self.queries_dir.iterdir():
            if item.is_dir() and not item.name.startswith('_') and not item.name.startswith('.'):
                # Check if it has at least one .scm file
                if any(item.glob('*.scm')):
                    languages.append(item.name)
        return sorted(languages)

    def list_queries(self, language: str) -> List[str]:
        """List available query types for a language."""
        canonical = self._resolve_language(language)
        bundle = self.load_bundle(canonical)
        return [qt for qt in self.QUERY_TYPES if bundle.has_query(qt)]

    def get_validation_errors(self) -> Dict[str, List[str]]:
        """Get all validation errors encountered during loading."""
        return self._validation_errors.copy()

    def clear_cache(self):
        """Clear the query cache."""
        self._cache.clear()
        self._validation_errors.clear()

    def validate_query(self, query_text: str, language_obj) -> bool:
        """
        Validate a query against a tree-sitter language.

        Args:
            query_text: The .scm query text
            language_obj: tree-sitter Language object

        Returns:
            True if valid, raises exception otherwise
        """
        try:
            import tree_sitter
            tree_sitter.Query(language_obj, query_text)
            return True
        except Exception as e:
            raise ValueError(f"Invalid query: {e}")

def get_query_loader() -> QueryLoader:
    """Get the singleton QueryLoader instance."""
    global _loader
    if _loader is None:
        _loader = QueryLoader()
    return _loader

def get_symbols_query(language: str) -> Optional[str]:
    """Convenience function to get symbols query for a language."""
    return get_query_loader().load_query(language, 'symbols')

def get_locals_query(language: str) -> Optional[str]:
    """Convenience function to get locals query for a language."""
    return get_query_loader().load_query(language, 'locals')

class PythonASTExtractor:
    """Handles parsing and extraction of Python code using the `ast` module."""

    def __init__(self, classifier):
        self.classifier = classifier

    def extract_particles_ast(self, content: str, file_path: str, include_depth_metrics: bool = False) -> Tuple[List[Dict], Dict[str, Any]]:
        """Extract particles using Python's AST module (faster/more accurate for Python)."""
        particles = []
        depth_metrics = {}
        try:
            tree = ast.parse(content)

            if include_depth_metrics:
                depth_metrics = self._measure_ast_depth(tree)

            lines = content.splitlines()

            # Use recursive or iterative based on depth/preference
            # For now, default to recursive as it's cleaner, unless depth is huge
            particles = self._extract_recursive(tree, file_path, lines)

        except Exception as e:
            # Fallback or empty if parse fails
            pass

        return particles, depth_metrics

    def _measure_ast_depth(self, tree: ast.AST) -> Dict[str, int]:
        """Measure AST depth without recursion to avoid stack limits."""
        max_depth = 0
        node_count = 0
        stack = [(tree, 1)]
        while stack:
            node, depth = stack.pop()
            node_count += 1
            if depth > max_depth:
                max_depth = depth
            for child in ast.iter_child_nodes(node):
                stack.append((child, depth + 1))
        return {"node_count": node_count, "max_depth": max_depth}

    def _extract_recursive(self, tree: ast.AST, file_path: str, lines: List[str]) -> List[Dict]:
        """Recursive AST traversal for Python symbols."""
        particles: List[Dict[str, Any]] = []
        class_stack: List[str] = []
        func_stack: List[str] = []

        # Capture self for closure usage in Visitor
        classifier = self.classifier
        extractor = self

        def evidence_for_line(line_no: int) -> str:
            idx = max(0, int(line_no or 1) - 1)
            if idx >= len(lines):
                return ""
            return (lines[idx] or "").strip()

        class Visitor(ast.NodeVisitor):
            def visit_ClassDef(self, node: ast.ClassDef):
                class_name = getattr(node, "name", "") or ""
                line_no = getattr(node, "lineno", 0) or 0
                parent = class_stack[-1] if class_stack else (func_stack[-1] if func_stack else "")

                base_classes = extractor._get_base_class_names(node)
                decorators = extractor._get_decorators(node)

                particles.append(
                    classifier.classify_extracted_symbol(
                        name=class_name,
                        symbol_kind="class",
                        file_path=file_path,
                        line_num=line_no,
                        evidence=evidence_for_line(line_no),
                        parent=parent,
                        base_classes=base_classes,
                        decorators=decorators,
                    )
                )

                class_stack.append(class_name)
                self.generic_visit(node)
                class_stack.pop()

            def visit_FunctionDef(self, node: ast.FunctionDef):
                func_name = getattr(node, "name", "") or ""
                line_no = getattr(node, "lineno", 0) or 0
                end_line_no = getattr(node, "end_lineno", line_no) or line_no

                if class_stack:
                    full_name = f"{class_stack[-1]}.{func_name}"
                    parent = class_stack[-1]
                    kind = "method"
                elif func_stack:
                    full_name = f"{func_stack[-1]}.{func_name}"
                    parent = func_stack[-1]
                    kind = "function"
                else:
                    full_name = func_name
                    parent = ""
                    kind = "function"

                decorators = extractor._get_decorators(node)

                # Extract lossless fields
                body_source = extractor._get_function_body(node, lines)
                params = extractor._get_function_params(node)
                docstring = extractor._get_docstring(node)
                return_type = extractor._get_return_type(node)

                particles.append(
                    classifier.classify_extracted_symbol(
                        name=full_name,
                        symbol_kind=kind,
                        file_path=file_path,
                        line_num=line_no,
                        end_line=end_line_no,
                        evidence=evidence_for_line(line_no),
                        parent=parent,
                        decorators=decorators,
                        body_source=body_source,
                        params=params,
                        docstring=docstring,
                        return_type=return_type,
                    )
                )

                func_stack.append(func_name)
                self.generic_visit(node)
                func_stack.pop()

            def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef):
                self.visit_FunctionDef(node)  # type: ignore[arg-type]

        Visitor().visit(tree)
        return particles

    def _get_base_class_names(self, node: ast.ClassDef) -> List[str]:
        """Extract base class names from a Python class definition."""
        bases = []
        for base in node.bases:
            if isinstance(base, ast.Name):
                bases.append(base.id)
            elif isinstance(base, ast.Attribute):
                bases.append(base.attr)
            elif isinstance(base, ast.Subscript):
                if isinstance(base.value, ast.Name):
                    bases.append(base.value.id)
                elif isinstance(base.value, ast.Attribute):
                    bases.append(base.value.attr)
        return bases

    def _get_decorators(self, node: Any) -> List[str]:
        """Extract decorator names from a node."""
        decorators = []
        for decorator in getattr(node, "decorator_list", []):
            try:
                if isinstance(decorator, ast.Name):
                    decorators.append(decorator.id)
                elif isinstance(decorator, ast.Attribute):
                    parts = []
                    while isinstance(decorator, ast.Attribute):
                        parts.append(decorator.attr)
                        decorator = decorator.value
                    if isinstance(decorator, ast.Name):
                        parts.append(decorator.id)
                    decorators.append(".".join(reversed(parts)))
                elif isinstance(decorator, ast.Call):
                    if isinstance(decorator.func, ast.Name):
                        decorators.append(decorator.func.id)
                    elif isinstance(decorator.func, ast.Attribute):
                        parts = []
                        curr = decorator.func
                        while isinstance(curr, ast.Attribute):
                            parts.append(curr.attr)
                            curr = curr.value
                        if isinstance(curr, ast.Name):
                            parts.append(curr.id)
                        decorators.append(".".join(reversed(parts)))
            except Exception:
                pass
        return decorators

    def _get_function_body(self, node: Any, lines: List[str]) -> str:
        """Extract function body source code for lossless regeneration."""
        try:
            start = getattr(node, "lineno", 0) - 1
            end = getattr(node, "end_lineno", start + 1)
            if start >= 0 and end <= len(lines):
                return "\n".join(lines[start:end])
        except Exception:
            pass
        return ""

    def _get_function_params(self, node: Any) -> List[Dict[str, str]]:
        """Extract function parameters with types and defaults."""
        params = []
        try:
            args = getattr(node, "args", None)
            if not args:
                return params

            defaults = args.defaults or []
            num_defaults = len(defaults)
            num_args = len(args.args)

            for i, arg in enumerate(args.args):
                param = {"name": arg.arg}
                if arg.annotation:
                    param["type"] = ast.unparse(arg.annotation)

                default_idx = i - (num_args - num_defaults)
                if default_idx >= 0 and default_idx < len(defaults):
                    param["default"] = ast.unparse(defaults[default_idx])

                params.append(param)

            if args.vararg:
                param = {"name": f"*{args.vararg.arg}"}
                if args.vararg.annotation:
                    param["type"] = ast.unparse(args.vararg.annotation)
                params.append(param)

            if args.kwarg:
                param = {"name": f"**{args.kwarg.arg}"}
                if args.kwarg.annotation:
                    param["type"] = ast.unparse(args.kwarg.annotation)
                params.append(param)
        except Exception:
            pass
        return params

    def _get_docstring(self, node: Any) -> str:
        try:
            return ast.get_docstring(node) or ""
        except Exception:
            return ""

    def _get_return_type(self, node: Any) -> str:
        try:
            if hasattr(node, "returns") and node.returns:
                return ast.unparse(node.returns)
        except Exception:
            pass
        return ""

class SymbolClassifier:
    """Classifies code symbols based on names, inheritance, and decorators."""

    # Prefix patterns for function classification
    PREFIX_PATTERNS = {
        'test_': ('Test', 90),
        'get_': ('Query', 85),
        'fetch_': ('Query', 85),
        'find_': ('Query', 85),
        'load_': ('Query', 85),
        'set_': ('Command', 85),
        'update_': ('Command', 85),
        'delete_': ('Command', 85),
        'remove_': ('Command', 85),
        'add_': ('Command', 85),
        'create_': ('Factory', 85),
        'build_': ('Factory', 85),
        'make_': ('Factory', 85),
        'validate_': ('Validator', 85),
        'check_': ('Validator', 85),
        'is_': ('Specification', 85),
        'has_': ('Specification', 85),
        'can_': ('Specification', 85),
        'handle_': ('EventHandler', 85),
        'on_': ('EventHandler', 85),
        'process_': ('Service', 80),
        'execute_': ('UseCase', 80),
        'convert_': ('Mapper', 80),
        'transform_': ('Mapper', 80),
        'to_': ('Mapper', 80),
        'from_': ('Factory', 80),
        '_': ('Internal', 70),
    }

    # Suffix patterns for class classification
    SUFFIX_PATTERNS = {
        'Service': ('Service', 90),
        'Repository': ('Repository', 90),
        'Controller': ('Controller', 90),
        'Handler': ('EventHandler', 85),
        'Factory': ('Factory', 85),
        'Builder': ('Builder', 85),
        'Mapper': ('Mapper', 85),
        'Validator': ('Validator', 85),
        'Entity': ('Entity', 85),
        'DTO': ('DTO', 85),
        'Command': ('Command', 85),
        'Query': ('Query', 85),
        'Event': ('DomainEvent', 85),
        'Policy': ('Policy', 85),
        'Specification': ('Specification', 85),
        'Exception': ('Exception', 85),
        'Error': ('Exception', 80),
        'Test': ('Test', 85),
        'Mock': ('Fixture', 80),
        'Stub': ('Fixture', 80),
        'Fake': ('Fixture', 80),
        'Config': ('Configuration', 80),
        'Settings': ('Configuration', 80),
    }

    # Dunder method mappings
    DUNDER_MAPPINGS = {
        '__init__': ('Lifecycle', 95),
        '__new__': ('Factory', 95),
        '__del__': ('Lifecycle', 95),
        '__str__': ('Utility', 90),
        '__repr__': ('Utility', 90),
        '__eq__': ('Specification', 90),
        '__hash__': ('Utility', 90),
        '__iter__': ('Iterator', 90),
        '__next__': ('Iterator', 90),
        '__getitem__': ('Query', 90),
        '__setitem__': ('Command', 90),
        '__call__': ('Command', 90),
        '__enter__': ('Lifecycle', 90),
        '__exit__': ('Lifecycle', 90),
    }

    def classify(
        self,
        name: str,
        kind: SymbolKind,
        file_path: str,
        line: int,
        decorators: List[str] = None,
        base_classes: List[str] = None,
        evidence: str = "",
    ) -> ClassifiedSymbol:
        """Classify a symbol based on all available evidence."""
        decorators = decorators or []
        base_classes = base_classes or []

        # Try classification in order of confidence
        role, confidence = self._classify_by_inheritance(base_classes)

        if confidence < 90:
            dec_role, dec_conf = self._classify_by_decorators(decorators)
            if dec_conf > confidence:
                role, confidence = dec_role, dec_conf

        if confidence < 85:
            name_role, name_conf = self._classify_by_name(name, kind)
            if name_conf > confidence:
                role, confidence = name_role, name_conf

        if confidence < 70:
            ev_role, ev_conf = self._classify_by_evidence(evidence)
            if ev_conf > confidence:
                role, confidence = ev_role, ev_conf

        return ClassifiedSymbol(
            name=name,
            kind=kind,
            role=role,
            confidence=confidence,
            file_path=file_path,
            line=line,
            decorators=decorators,
            base_classes=base_classes,
            evidence=evidence,
        )

    def _classify_by_inheritance(self, base_classes: List[str]) -> Tuple[str, float]:
        """Classify by DDD base class inheritance (highest confidence)."""
        for base in base_classes:
            # Handle full path like module.Entity -> Entity
            simple_name = base.split('.')[-1]
            if simple_name in DDD_BASE_CLASS_MAPPINGS:
                return (DDD_BASE_CLASS_MAPPINGS[simple_name], 99)
        return ("Unknown", 0)

    def _classify_by_decorators(self, decorators: List[str]) -> Tuple[str, float]:
        """Classify by decorator patterns."""
        for dec in decorators:
            # Handle full decorator path
            simple_name = dec.split('.')[-1].lower()
            if simple_name in DECORATOR_MAPPINGS:
                return (DECORATOR_MAPPINGS[simple_name], 90)

            # Check partial matches
            for pattern, role in DECORATOR_MAPPINGS.items():
                if pattern in dec.lower():
                    return (role, 85)

        return ("Unknown", 0)

    def _classify_by_name(self, name: str, kind: SymbolKind) -> Tuple[str, float]:
        """Classify by naming conventions."""
        name_lower = name.lower()
        short_name = name.split('.')[-1] if '.' in name else name
        short_lower = short_name.lower()

        # Check dunder methods
        if short_lower in self.DUNDER_MAPPINGS:
            return self.DUNDER_MAPPINGS[short_lower]

        # Check prefix patterns
        for prefix, (role, conf) in self.PREFIX_PATTERNS.items():
            if short_lower.startswith(prefix):
                return (role, conf)

        # Check suffix patterns (case-insensitive)
        for suffix, (role, conf) in self.SUFFIX_PATTERNS.items():
            if short_name.endswith(suffix) or short_lower.endswith(suffix.lower()):
                return (role, conf)

        # Default based on kind
        if kind == SymbolKind.CLASS:
            return ("DTO", 50)
        elif kind == SymbolKind.FUNCTION:
            return ("Utility", 50)

        return ("Unknown", 0)

    def _classify_by_evidence(self, evidence: str) -> Tuple[str, float]:
        """Classify by code evidence (body patterns)."""
        if not evidence:
            return ("Unknown", 0)

        evidence_lower = evidence.lower()

        # Database patterns
        if any(x in evidence_lower for x in ['select', 'insert', 'update ', 'delete from']):
            return ("Repository", 75)

        # HTTP patterns
        if any(x in evidence_lower for x in ['request', 'response', 'http', 'json']):
            return ("Controller", 70)

        # Validation patterns
        if any(x in evidence_lower for x in ['raise', 'assert', 'error', 'exception']):
            return ("Validator", 65)

        return ("Unknown", 0)

class PythonASTParser:
    """Parses Python source code using the AST module."""

    # Maximum depth before switching to iterative traversal
    MAX_RECURSIVE_DEPTH = 500

    def __init__(self):
        self.symbols: List[PythonSymbol] = []
        self.lines: List[str] = []

    def parse(self, content: str) -> List[PythonSymbol]:
        """Parse Python content and extract all symbols."""
        self.symbols = []
        self.lines = content.splitlines()

        try:
            tree = ast.parse(content)
        except SyntaxError:
            return []

        # Measure depth to choose traversal strategy
        depth = self._measure_depth(tree)

        if depth < self.MAX_RECURSIVE_DEPTH:
            self._extract_recursive(tree)
        else:
            self._extract_iterative(tree)

        return self.symbols

    def _measure_depth(self, tree: ast.AST) -> int:
        """Measure AST depth without recursion."""
        max_depth = 0
        stack = [(tree, 0)]

        while stack:
            node, depth = stack.pop()
            max_depth = max(max_depth, depth)

            for child in ast.iter_child_nodes(node):
                stack.append((child, depth + 1))

        return max_depth

    def _extract_recursive(self, tree: ast.AST, parent: str = ""):
        """Recursive extraction for normal-depth trees."""

        class Visitor(ast.NodeVisitor):
            def __init__(self_v, parser, parent_name):
                self_v.parser = parser
                self_v.parent = parent_name

            def visit_ClassDef(self_v, node: ast.ClassDef):
                symbol = self_v.parser._extract_class(node, self_v.parent)
                self_v.parser.symbols.append(symbol)

                # Visit methods with class as parent
                for child in node.body:
                    if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
                        method_symbol = self_v.parser._extract_function(child, node.name)
                        self_v.parser.symbols.append(method_symbol)
                    elif isinstance(child, ast.ClassDef):
                        Visitor(self_v.parser, node.name).visit(child)

            def visit_FunctionDef(self_v, node: ast.FunctionDef):
                if not self_v.parent:  # Only top-level functions
                    symbol = self_v.parser._extract_function(node, "")
                    self_v.parser.symbols.append(symbol)

            def visit_AsyncFunctionDef(self_v, node: ast.AsyncFunctionDef):
                if not self_v.parent:
                    symbol = self_v.parser._extract_function(node, "")
                    self_v.parser.symbols.append(symbol)

        Visitor(self, parent).visit(tree)

    def _extract_iterative(self, tree: ast.AST):
        """Iterative extraction for deep trees (avoids recursion limits)."""
        stack = [(tree, "")]

        while stack:
            node, parent = stack.pop()

            if isinstance(node, ast.ClassDef):
                symbol = self._extract_class(node, parent)
                self.symbols.append(symbol)

                # Add children with class as parent
                for child in reversed(node.body):
                    if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
                        method_symbol = self._extract_function(child, node.name)
                        self.symbols.append(method_symbol)
                    elif isinstance(child, ast.ClassDef):
                        stack.append((child, node.name))

            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                if not parent:  # Only top-level
                    symbol = self._extract_function(node, "")
                    self.symbols.append(symbol)

            elif isinstance(node, ast.Module):
                for child in reversed(node.body):
                    stack.append((child, parent))

    def _extract_class(self, node: ast.ClassDef, parent: str) -> PythonSymbol:
        """Extract a class symbol."""
        return PythonSymbol(
            name=node.name,
            kind="class",
            line=node.lineno,
            end_line=getattr(node, 'end_lineno', node.lineno),
            parent=parent,
            decorators=self._get_decorators(node),
            base_classes=self._get_base_classes(node),
            docstring=self._get_docstring(node),
        )

    def _extract_function(self, node, parent: str) -> PythonSymbol:
        """Extract a function/method symbol."""
        return PythonSymbol(
            name=node.name,
            kind="method" if parent else "function",
            line=node.lineno,
            end_line=getattr(node, 'end_lineno', node.lineno),
            parent=parent,
            decorators=self._get_decorators(node),
            params=self._get_params(node),
            return_type=self._get_return_type(node),
            docstring=self._get_docstring(node),
            body_source=self._get_body_source(node),
        )

    def _get_decorators(self, node) -> List[str]:
        """Extract decorator names."""
        decorators = []
        for dec in node.decorator_list:
            if isinstance(dec, ast.Name):
                decorators.append(dec.id)
            elif isinstance(dec, ast.Attribute):
                decorators.append(f"{self._get_attribute_name(dec)}")
            elif isinstance(dec, ast.Call):
                if isinstance(dec.func, ast.Name):
                    decorators.append(dec.func.id)
                elif isinstance(dec.func, ast.Attribute):
                    decorators.append(self._get_attribute_name(dec.func))
        return decorators

    def _get_attribute_name(self, node: ast.Attribute) -> str:
        """Get full attribute name like pytest.mark.parametrize."""
        parts = [node.attr]
        current = node.value
        while isinstance(current, ast.Attribute):
            parts.append(current.attr)
            current = current.value
        if isinstance(current, ast.Name):
            parts.append(current.id)
        return '.'.join(reversed(parts))

    def _get_base_classes(self, node: ast.ClassDef) -> List[str]:
        """Extract base class names."""
        bases = []
        for base in node.bases:
            if isinstance(base, ast.Name):
                bases.append(base.id)
            elif isinstance(base, ast.Attribute):
                bases.append(self._get_attribute_name(base))
        return bases

    def _get_params(self, node) -> List[Dict[str, str]]:
        """Extract function parameters with types and defaults."""
        params = []
        args = node.args

        # Calculate defaults offset
        defaults_offset = len(args.args) - len(args.defaults)

        for i, arg in enumerate(args.args):
            param = {"name": arg.arg}

            # Type annotation
            if arg.annotation:
                param["type"] = ast.unparse(arg.annotation) if hasattr(ast, 'unparse') else ""

            # Default value
            default_idx = i - defaults_offset
            if default_idx >= 0 and default_idx < len(args.defaults):
                try:
                    param["default"] = ast.unparse(args.defaults[default_idx]) if hasattr(ast, 'unparse') else "..."
                except:
                    param["default"] = "..."

            params.append(param)

        # *args
        if args.vararg:
            params.append({"name": f"*{args.vararg.arg}"})

        # **kwargs
        if args.kwarg:
            params.append({"name": f"**{args.kwarg.arg}"})

        return params

    def _get_return_type(self, node) -> str:
        """Extract return type annotation."""
        if node.returns:
            try:
                return ast.unparse(node.returns) if hasattr(ast, 'unparse') else ""
            except:
                return ""
        return ""

    def _get_docstring(self, node) -> str:
        """Extract docstring from function or class."""
        return ast.get_docstring(node) or ""

    def _get_body_source(self, node) -> str:
        """Extract body source code."""
        if not self.lines:
            return ""

        try:
            start = node.lineno - 1
            end = getattr(node, 'end_lineno', start + 1)
            return '\n'.join(self.lines[start:end])
        except:
            return ""

def parse_python(content: str) -> List[PythonSymbol]:
    """Convenience function to parse Python content."""
    parser = PythonASTParser()
    return parser.parse(content)

class UserRepository(BaseRepository):
    """Repository for User entities."""

    def get_by_id(self, user_id: int) -> Optional[User]:
        """Get user by ID."""
        return self.session.query(User).get(user_id)

    def save(self, user: User) -> User:
